import{_ as t,o,c as r,ag as a}from"./chunks/framework.DLWhSH9p.js";const h=JSON.parse('{"title":"Mobile Setup","description":"","frontmatter":{},"headers":[],"relativePath":"mobile/setup.md","filePath":"mobile/setup.md"}'),n={name:"mobile/setup.md"};function i(s,e,l,c,d,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="mobile-setup" tabindex="-1">Mobile Setup <a class="header-anchor" href="#mobile-setup" aria-label="Permalink to &quot;Mobile Setup&quot;">​</a></h1><h2 id="install-the-apk" tabindex="-1">Install the APK <a class="header-anchor" href="#install-the-apk" aria-label="Permalink to &quot;Install the APK&quot;">​</a></h2><ol><li>Download the latest APK from the <a href="https://expo.dev/accounts/xander-rudolph/projects/craft" target="_blank" rel="noreferrer">EAS build page</a>.</li><li>Transfer to your phone and open it. Allow &quot;Unknown sources&quot; in Android settings the first time.</li><li>Open <strong>Craft</strong>, sign in with your Keycloak account.</li><li>Open <strong>Settings</strong> → <strong>Server URL</strong> and point it at your CRAFT server (e.g. <code>https://craft.example.com/studio</code>).</li><li>Tap <strong>Test Connection</strong> — you should see a green check.</li></ol><h2 id="server-connection" tabindex="-1">Server Connection <a class="header-anchor" href="#server-connection" aria-label="Permalink to &quot;Server Connection&quot;">​</a></h2><p>The mobile app talks to the same Express backend as the web app:</p><ul><li><strong>Hosted CRAFT</strong> — use your ingress hostname (e.g. <code>https://craft.example.com/studio</code>). Works from anywhere on the public internet.</li><li><strong>Local network</strong> — use your server&#39;s LAN IP and port (e.g. <code>http://192.168.1.42:3000</code>). Phone and server must be on the same network (Wi-Fi or VPN like Tailscale).</li></ul><p>The server URL is saved between launches.</p><div class="tip custom-block"><p class="custom-block-title">Finding your LAN IP</p><p>On the machine running CRAFT, run <code>ipconfig</code> (Windows) or <code>ifconfig</code> / <code>ip addr</code> (Mac/Linux). Use the Wi-Fi adapter&#39;s IPv4 address.</p></div><div class="warning custom-block"><p class="custom-block-title">HTTP on Android</p><p>Android blocks cleartext HTTP by default. The Craft APK is built with <code>usesCleartextTraffic: true</code> so local-network HTTP works without certificate setup.</p></div><h2 id="building-from-source" tabindex="-1">Building from source <a class="header-anchor" href="#building-from-source" aria-label="Permalink to &quot;Building from source&quot;">​</a></h2><p>Building the APK yourself, running the app in Expo Go, or making changes to the mobile codebase is covered in the <a href="https://github.com/Mossworks-Labs/craft/blob/main/README.md#mobile-app-android" target="_blank" rel="noreferrer">project README</a> — that&#39;s contributor territory rather than user-facing setup.</p>',11)])])}const m=t(n,[["render",i]]);export{h as __pageData,m as default};
